import { PLAN_LIMITS } from "../config/plan-limits.js";
async function checkProfessionalLimit(tenantId: string) {
  const [t] = await db.select({ plan: tenants.planTier, max: tenants.maxProfessionals }).from(tenants).where(eq(tenants.id, tenantId));
  const limit = t?.max ?? PLAN_LIMITS[t?.plan ?? "free"]?.professionals ?? 1;
  const [{ count }] = await db.select({ count: sql`count(*)` }).from(professionals).where(and(eq(professionals.tenantId, tenantId), eq(professionals.isActive, true)));
  return { allowed: Number(count) < limit, limit, current: Number(count) };
}

async function checkClientLimit(tenantId: string) {
  const [t] = await db.select({ plan: tenants.planTier, max: tenants.maxClients }).from(tenants).where(eq(tenants.id, tenantId));
  const limit = t?.max ?? PLAN_LIMITS[t?.plan ?? "free"]?.clients ?? 100;
  const [{ count }] = await db.select({ count: sql`count(*)` }).from(clients).where(and(eq(clients.tenantId, tenantId), isNull(clients.deletedAt)));
  return { allowed: Number(count) < limit, limit, current: Number(count) };
}

export async function packagesModule(fastify: FastifyInstance) {
  fastify.get("/packages", { preHandler: [authenticate] }, async (req: any, reply) => {
    const { tenantId } = req.tenantContext;
    const { clientId, status } = req.query as any;
    const cond = [eq(packages.tenantId, tenantId), isNull(packages.deletedAt)];
    if (clientId) cond.push(eq(packages.clientId, clientId));
    if (status)   cond.push(eq(packages.status, status));
    const data = await db.select().from(packages).where(and(...cond)).orderBy(desc(packages.createdAt));
    return reply.send({ success: true, data, total: data.length });
  });

  fastify.post("/packages", { preHandler: [authenticate] }, async (req: any, reply) => {
    const { tenantId, userId } = req.tenantContext;
    const body = req.body as any;
    const [pkg] = await db.insert(packages).values({
      tenantId, createdBy: userId, updatedBy: userId,
      clientId: body.clientId,
      name: body.name,
      totalSessions: Number(body.totalSessions),
      usedSessions: 0,
      remainingSessions: Number(body.totalSessions),
      totalValue: String(body.totalValue),
      status: "active",
      expiresAt: body.expiresAt ? new Date(body.expiresAt) : null,
    }).returning();
    return reply.status(201).send({ success: true, data: pkg });
  });
  fastify.post("/packages/:id/use-session", { preHandler: [authenticate] }, async (req: any, reply) => {
    const { tenantId, userId } = req.tenantContext;
    const [pkg] = await db.select().from(packages).where(and(eq(packages.id, req.params.id), eq(packages.tenantId, tenantId)));
    if (!pkg || pkg.remainingSessions <= 0) {
      return reply.status(400).send({ success: false, error: "Pacote sem sessoes disponiveis" });
    }
  });
}

