export async function authModule(fastify: FastifyInstance) {
    fastify.patch("/auth/me/profile", { preHandler: [authenticate] }, async (req: any, reply: any) => {
    const { tenantId } = req.tenantContext;
    const { name, logoUrl, coverUrl, primaryColor, whatsapp, instagram, facebook, phone, addressStreet, addressCity, addressState, addressZip, website, businessHours, hasWifi, hasParking } = req.body as any;
    const updateData: any = { updatedAt: new Date() };
    if (name !== undefined)          updateData.name = name;
    if (logoUrl !== undefined)        updateData.logoUrl = logoUrl;
    if (coverUrl !== undefined)       updateData.coverUrl = coverUrl;
    if (primaryColor !== undefined)   updateData.primaryColor = primaryColor;
    if (whatsapp !== undefined)       updateData.whatsapp = whatsapp;
    if (instagram !== undefined)      updateData.instagram = instagram;
    if (facebook !== undefined)       updateData.facebook = facebook;
    if (phone !== undefined)          updateData.phone = phone;
    if (addressStreet !== undefined)  updateData.addressStreet = addressStreet;
    if (addressCity !== undefined)    updateData.addressCity = addressCity;
    if (addressState !== undefined)   updateData.addressState = addressState;
    if (addressZip !== undefined)     updateData.addressZip = addressZip;
    if (website !== undefined)        updateData.website = website;
    if (businessHours !== undefined)  updateData.businessHours = businessHours;
    if (hasWifi !== undefined)        updateData.hasWifi = hasWifi;
    if (hasParking !== undefined)     updateData.hasParking = hasParking;
    const [updated] = await db.update(tenants).set(updateData).where(eq(tenants.id, tenantId)).returning();
    // Geocoding automatico se endereco foi alterado (fire and forget)
    if (addressCity || addressStreet) {
      (async () => {
        try {
          const city  = addressCity  ?? updated.addressCity;
          const state = addressState ?? updated.addressState;
          const street = addressStreet ?? updated.addressStreet;
          const q = [street, city, state, "Brasil"].filter(Boolean).join(", ");
          const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=1`, {
            headers: { "User-Agent": "ZenSalon/1.0 (contato@zensalon.com.br)" }
          });
          const geoJson = await geoRes.json();
          if (geoJson?.[0]) {
            await db.update(tenants).set({ lat: geoJson[0].lat, lng: geoJson[0].lon }).where(eq(tenants.id, tenantId));
            console.log(`[GEO] ${updated.name}: ${geoJson[0].lat}, ${geoJson[0].lon}`);
          }
        } catch (e: any) { console.error("[GEO] Erro geocoding:", e.message); }
      })();
    }
    return reply.send({ success: true, data: updated });
  });
  fastify.patch("/auth/me/settings", { preHandler: [authenticate] }, async (req: any, reply: any) => {
    const { tenantId } = req.tenantContext;
    const [tenant] = await db.select().from(tenants).where(eq(tenants.id, tenantId));
    const newSettings = { ...(tenant.settings ?? {}), ...(req.body as any) };
    const [updated] = await db.update(tenants).set({ settings: newSettings, updatedAt: new Date() }).where(eq(tenants.id, tenantId)).returning();
    return reply.send({ success: true, data: updated });
  });

  fastify.get("/auth/me", { preHandler: [authenticate] }, async (req: any, reply) => {
    try {
    const { tenantId } = req.tenantContext;
    const [tenant] = await db.select({
      id:          tenants.id,
      name:        tenants.name,
      planTier:    tenants.planTier,
      isActive:    tenants.isActive,
      trialEndsAt: tenants.trialEndsAt,
      businessType: tenants.businessType,
      slug:          tenants.slug,
        logoUrl:       tenants.logoUrl,
        coverUrl:      tenants.coverUrl,
        primaryColor:  tenants.primaryColor,
        whatsapp:      tenants.whatsapp,
        instagram:     tenants.instagram,
        facebook:      tenants.facebook,
        phone:         tenants.phone,
        website:       tenants.website,
        addressStreet: tenants.addressStreet,
        addressCity:   tenants.addressCity,
        addressState:  tenants.addressState,
        addressZip:    tenants.addressZip,
    }).from(tenants).where(eq(tenants.id, tenantId));
    if (!tenant) return reply.status(404).send({ success: false, error: "Tenant nao encontrado" });
    const now = new Date();
    const trialEnd = tenant?.trialEndsAt ? new Date(tenant.trialEndsAt) : null;
    const daysLeft = trialEnd ? Math.ceil((trialEnd.getTime() - now.getTime()) / 86400000) : null;
    if (!tenant) return reply.status(404).send({ success: false, error: "Tenant nao encontrado" });
    return reply.send({ success: true, data: { ...tenant, daysLeft } });
    } catch(e: any) { console.error("auth/me error:", e.message, e.stack); return reply.status(500).send({ success: false, error: e.message }); }
  });
  fastify.post("/auth/register", async (req: any, reply) => {
    const { salonName, ownerName, email, password, whatsapp, businessType, cpfCnpj,
      addressStreet, addressCity, addressState, addressZip, hasWifi, hasParking } = req.body as any;
    if (!salonName || !ownerName || !email || !password) {
      return reply.status(400).send({ success: false, error: "Todos os campos sâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ãºo obrigatâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬â”‚rios" });
      return reply.status(400).send({ success: false, error: "Todos os campos sâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ãºo obrigatâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬â”‚rios" });
    }
    if (password.length < 6) {
      return reply.status(400).send({ success: false, error: "Senha deve ter no mâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Â¡nimo 6 caracteres" });
    }

    // Criar usuâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ã­rio via API REST do Supabase (sem SDK)
    const supabaseUrl = process.env.SUPABASE_URL!;
    const serviceKey  = process.env.SUPABASE_SERVICE_ROLE_KEY!;

    const authRes = await fetch(`${supabaseUrl}/auth/v1/admin/users`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${serviceKey}`,
        "apikey": serviceKey,
      },
      body: JSON.stringify({ email, password, email_confirm: true }),
    });

    const authData = await authRes.json() as any;

    if (!authRes.ok) {
      return reply.status(400).send({ success: false, error: authData.message ?? "Erro ao criar usuâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ã­rio" });
    }

    const authUserId = authData.id;

    try {
      const trialEndsAt = new Date();
      trialEndsAt.setDate(trialEndsAt.getDate() + 15);

      const categoriesByType = {
        beauty_salon: ["Cabelo", "Unhas", "Estetica", "Maquiagem", "Massagem"],
        aesthetics_clinic: ["Limpeza de Pele", "Peeling", "Microagulhamento", "Depilacao", "Massagem Estetica"],
        barbershop: ["Corte Masculino", "Barba", "Pigmentacao", "Sobrancelha Masculina", "Tratamento Capilar"],
      }
      const resolvedBusinessType = (businessType && categoriesByType[businessType as keyof typeof categoriesByType]) ? businessType : "beauty_salon"
      const defaultCategories = categoriesByType[resolvedBusinessType as keyof typeof categoriesByType]
      const [tenant] = await db.insert(tenants).values({
        name: salonName,
        slug: salonName.toLowerCase().replace(/[^a-z0-9]/g, "-").replace(/-+/g, "-").replace(/^-|-$/g, "") + "-" + Math.random().toString(36).slice(2,7),
        email,
        whatsapp: whatsapp ?? null,
        planTier: "trial",
        isActive: true,
        trialEndsAt,
        businessType: resolvedBusinessType,
        addressStreet: addressStreet ?? null,
        addressCity: addressCity ?? null,
        addressState: addressState ?? null,
        addressZip: addressZip ?? null,
        hasWifi: hasWifi ?? false,
        hasParking: hasParking ?? false,
        settings: cpfCnpj ? { cpfCnpj } : {},
      }).returning();
      await db.insert(userProfiles).values({
        tenantId: tenant.id,
        authUserId,
        fullName: ownerName,
        email,
        role: "owner",
        isActive: true,
      });
      await db.insert(financialAccounts).values({
        tenantId: tenant.id,
        name: "Caixa Principal",
        type: "cash",
        balance: "0",
        isDefault: true,
        isActive: true,
      });

      await db.insert(serviceCategories).values(
        defaultCategories.map((name, i) => ({
          tenantId: tenant.id,
          name,
          isActive: true,
          sortOrder: i + 1,
        }))
      );

      // Geocoding automatico via Nominatim (fire and forget)
      if (addressCity || addressStreet) {
        (async () => {
          try {
            const q = [addressStreet, addressCity, addressState, "Brasil"].filter(Boolean).join(", ");
            const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=1`, {
              headers: { "User-Agent": "ZenSalon/1.0 (contato@zensalon.com.br)" }
            });
            const geoJson = await geoRes.json();
            if (geoJson?.[0]) {
              await db.update(tenants).set({
                lat: geoJson[0].lat,
                lng: geoJson[0].lon,
              }).where(eq(tenants.id, tenant.id));
              console.log(`[GEO] ${salonName}: ${geoJson[0].lat}, ${geoJson[0].lon}`);
            }
          } catch (e: any) { console.error("[GEO] Erro geocoding:", e.message); }
        })();
      }

      // Dispara e-mail de boas-vindas (fire and forget)
      try {
        const { sendWelcomeEmail } = await import('../modules/resend.module.js');
        await sendWelcomeEmail(email, salonName);
      } catch (emailErr: any) {
        console.error('[REGISTER] Falha no email:', emailErr.message);
      }

      return reply.status(201).send({
        success: true,
        data: {
          tenantId: tenant.id,
          salonName: tenant.name,
          email,
          message: "Salâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ãºo cadastrado com sucesso! Faâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Âºa login para continuar.",
        },
      });

    } catch (err: any) {
      // Remover usuâ”œÃ¢Ã£Ã†â”œÃ¥Ã”Ã‡Ã–â”œÃ¢Ã”Ã‡Ãœâ”œÃ©â”¬Ã­rio do Supabase se falhou
      await fetch(`${supabaseUrl}/auth/v1/admin/users/${authUserId}`, {
        method: "DELETE",
        headers: {
          "Authorization": `Bearer ${serviceKey}`,
          "apikey": serviceKey,
        },
      });
      console.error("[REGISTER ERROR]", err?.message, err?.stack);
      return reply.status(500).send({ success: false, error: err?.message ?? "Erro ao criar salao" });

    }
  });
}

